import React from "react";
import NavBar from "./NavBar";
import { Link } from 'react-router-dom';

const Header = () => {
    return(
        <header className="App-header">
            <div className="nav-area">
                <Link to = "/" className="logo">
                    Logo
                </Link>
                <NavBar />
            </div>
        </header>
    );
}

export default Header;